## TASK 3: DiceDuelUI.ts — NEW FILE

```ts
/**
 * @file DiceDuelUI.ts
 * @purpose Provides the Phaser UI components and animations for the Dice Duel game.
 * @author Agent 934
 * @date 2026-04-16
 * @license Proprietary
 */

import * as Phaser from 'phaser';
import type { DiceDuelState, DiceValue } from './DiceDuelLogic';

// --- Constants ---
const GAME_WIDTH = 390;
const GAME_HEIGHT = 844;

const GOLD = 0xc9a84c;
const GOLD_STR = '#c9a84c';
const DARK = 0x080812;
const DARK_STR = '#080812';
const AMBER = 0xff8c00;
const AMBER_STR = '#ff8c00';
const GREEN = 0x00ff00;
const RED = 0xff0000;

const FONT_FAMILY = 'Fredoka';

const TITLE_Y = 60;
const LABEL_YOU_Y = 140;
const LABEL_VS_Y = 350;
const LABEL_HOUSE_Y = 560;

const PLAYER_DICE_Y = 220;
const HOUSE_DICE_Y = 460;

const PLAYER_TOTAL_Y = 300;
const HOUSE_TOTAL_Y = 540;

const BUTTON_Y = 650;
const BUTTON_WIDTH = 220;
const BUTTON_HEIGHT = 66;
const BUTTON_RADIUS = 16;

const RESULT_TEXT_Y = 750;
const PLAY_AGAIN_BUTTON_Y = 800;

const DICE_SIZE = 96;
const DICE_SPACING = 10;
const DICE_BORDER_WIDTH = 3;
const DICE_CORNER_RADIUS = DICE_SIZE * 0.15; // Approx 14px for 96px dice
const DICE_DOT_RADIUS = 6;

const BET_DISPLAY_X = 10;
const BET_DISPLAY_Y = 16;

const BALANCE_DISPLAY_X = GAME_WIDTH - 10;
const BALANCE_DISPLAY_Y = 16;

export class DiceDuelUI {
  private scene: Phaser.Scene;
  private container: Phaser.GameObjects.Container;

  // UI Elements
  private playerDiceContainer!: Phaser.GameObjects.Container;
  private houseDiceContainer!: Phaser.GameObjects.Container;
  private playerTotalText!: Phaser.GameObjects.Text;
  private houseTotalText!: Phaser.GameObjects.Text;
  private rollButton!: Phaser.GameObjects.Container;
  private doubleDownButton!: Phaser.GameObjects.Container;
  private resultText!: Phaser.GameObjects.Text;
  private playAgainButton!: Phaser.GameObjects.Container;
  private betDisplay!: Phaser.GameObjects.Text;
  private balanceDisplay!: Phaser.GameObjects.Text;

  // Callbacks
  public onRollClicked?: () => void;
  public onDoubleDownClicked?: () => void;
  public onPlayAgainClicked?: () => void;

  /**
   * Creates an instance of DiceDuelUI.
   * @param scene The Phaser Scene to which this UI belongs.
   */
  constructor(scene: Phaser.Scene) {
    this.scene = scene;
    this.container = this.scene.add.container(0, 0);
  }

  /**
   * Initializes and displays all UI elements for the Dice Duel game.
   */
  public start(): void {
    this.createTitle();
    this.createLabels();
    this.createDiceAreas();
    this.createTotalDisplays();
    this.createButtons();
    this.createResultText();
    this.createBetAndBalanceDisplays();

    this.resetUI();
  }

  /**
   * Cleans up and destroys all UI elements created by this class.
   */
  public cleanup(): void {
    this.container.destroy();
  }

  /**
   * Creates the game title.
   */
  private createTitle(): void {
    const title = this.scene.add.text(GAME_WIDTH / 2, TITLE_Y, 'DICE DUEL', {
      fontFamily: FONT_FAMILY,
      fontSize: '48px',
      color: GOLD_STR,
      align: 'center',
      shadow: {
        offsetX: 3,
        offsetY: 3,
        color: DARK_STR,
        blur: 5,
        stroke: false,
        fill: true
      }
    }).setOrigin(0.5);
    this.container.add(title);
  }

  /**
   * Creates the 'YOU', 'VS', and 'HOUSE' labels.
   */
  private createLabels(): void {
    const createLabel = (y: number, text: string, color: string = GOLD_STR) => {
      const label = this.scene.add.text(GAME_WIDTH / 2, y, text, {
        fontFamily: FONT_FAMILY,
        fontSize: '32px',
        color: color,
        align: 'center',
        shadow: {
          offsetX: 2,
          offsetY: 2,
          color: DARK_STR,
          blur: 3,
          stroke: false,
          fill: true
        }
      }).setOrigin(0.5);
      this.container.add(label);
      return label;
    };

    createLabel(LABEL_YOU_Y, 'YOU');
    createLabel(LABEL_VS_Y, 'VS', '#aaaaaa'); // Lighter color for VS
    createLabel(LABEL_HOUSE_Y, 'HOUSE');
  }

  /**
   * Creates containers for player and house dice.
   */
  private createDiceAreas(): void {
    this.playerDiceContainer = this.scene.add.container(0, 0);
    this.houseDiceContainer = this.scene.add.container(0, 0);
    this.container.add([this.playerDiceContainer, this.houseDiceContainer]);
  }

  /**
   * Creates text displays for player and house totals.
   */
  private createTotalDisplays(): void {
    const createTotalText = (y: number, prefix: string) => {
      const text = this.scene.add.text(GAME_WIDTH / 2, y, `${prefix}: —`, {
        fontFamily: FONT_FAMILY,
        fontSize: '24px',
        color: GOLD_STR,
        align: 'center',
        shadow: {
          offsetX: 1,
          offsetY: 1,
          color: DARK_STR,
          blur: 2,
          stroke: false,
          fill: true
        }
      }).setOrigin(0.5);
      this.container.add(text);
      return text;
    };

    this.playerTotalText = createTotalText(PLAYER_TOTAL_Y, 'YOUR ROLL');
    this.houseTotalText = createTotalText(HOUSE_TOTAL_Y, 'HOUSE ROLL');
  }

  /**
   * Creates the ROLL, DOUBLE DOWN, and PLAY AGAIN buttons.
   */
  private createButtons(): void {
    this.rollButton = this.createButton(GAME_WIDTH / 2, BUTTON_Y, 'ROLL DICE', GOLD, DARK_STR, () => this.onRollClicked?.());
    this.doubleDownButton = this.createButton(GAME_WIDTH / 2, BUTTON_Y, 'DOUBLE DOWN', AMBER, DARK_STR, () => this.onDoubleDownClicked?.());
    this.playAgainButton = this.createButton(GAME_WIDTH / 2, PLAY_AGAIN_BUTTON_Y, 'PLAY AGAIN', GOLD, DARK_STR, () => this.onPlayAgainClicked?.());

    this.container.add([this.rollButton, this.doubleDownButton, this.playAgainButton]);
  }

  /**
   * Creates a generic rounded rectangle button.
   * @param x X-coordinate of the button center.
   * @param y Y-coordinate of the button center.
   * @param text The text to display on the button.
   * @param bgColor The background color of the button.
   * @param textColor The color of the button text.
   * @param callback The function to call when the button is clicked.
   * @returns A Phaser.GameObjects.Container representing the button.
   */
  private createButton(x: number, y: number, text: string, bgColor: number, textColor: string, callback: () => void): Phaser.GameObjects.Container {
    const graphics = this.scene.add.graphics();
    graphics.fillStyle(bgColor, 1);
    graphics.fillRoundedRect(-BUTTON_WIDTH / 2, -BUTTON_HEIGHT / 2, BUTTON_WIDTH, BUTTON_HEIGHT, BUTTON_RADIUS);

    const buttonText = this.scene.add.text(0, 0, text, {
      fontFamily: FONT_FAMILY,
      fontSize: '32px',
      color: textColor,
      align: 'center'
    }).setOrigin(0.5);

    const button = this.scene.add.container(x, y, [graphics, buttonText])
      .setSize(BUTTON_WIDTH, BUTTON_HEIGHT)
      .setInteractive({ useHandCursor: true })
      .on('pointerdown', () => {
        button.setScale(0.95);
      })
      .on('pointerup', () => {
        button.setScale(1);
        callback();
      })
      .on('pointerout', () => {
        button.setScale(1);
      });

    return button;
  }

  /**
   * Creates the result text display.
   */
  private createResultText(): void {
    this.resultText = this.scene.add.text(GAME_WIDTH / 2, RESULT_TEXT_Y, '', {
      fontFamily: FONT_FAMILY,
      fontSize: '48px',
